# Portfolio composition analyser
from dataclasses import dataclass
from collections import Counter

@dataclass
class PortfolioHealth:
    use_cases: list[UseCase]

    def composition(self) -> dict[str, int]:
        counts = Counter(uc.tier.value for uc in self.use_cases)
        return dict(counts)

    def health_assessment(self) -> list[str]:
        total = len(self.use_cases)
        if total == 0:
            return ["No use cases in portfolio"]

        comp = self.composition()
        t1 = comp.get(PortfolioTier.TIER_1_QUICK_WIN.value, 0)
        t2 = comp.get(PortfolioTier.TIER_2_STRATEGIC_BET.value, 0)
        t3 = comp.get(PortfolioTier.TIER_3_FILL_IN.value, 0)
        t4 = comp.get(PortfolioTier.TIER_4_REJECT.value, 0)

        signals = []
        if t1 / total > 0.70:
            signals.append("WARNING: >70% Tier 1 — few strategic bets in portfolio")
        if t2 / total > 0.50:
            signals.append("WARNING: >50% Tier 2 — governance overhead may exceed CoE capacity")
        if t3 > t1:
            signals.append("WARNING: More fill-ins than quick wins — BUs submitting low-value requests")
        if t4 == 0 and total > 5:
            signals.append("INFO: No Tier 4 rejections — verify intake scrutiny is adequate")
        if not signals:
            signals.append("Portfolio composition healthy")
        return signals

# Analyse the example portfolio from above
portfolio = PortfolioHealth(use_cases)
print("Portfolio composition:")
for tier, count in portfolio.composition().items():
    print(f"  {tier}: {count}")
print("\nHealth assessment:")
for signal in portfolio.health_assessment():
    print(f"  {signal}")
